/** NanoClaw mascot logo (PNG — too complex for inline SVG) */
function NanoClawLogo({ className, size = 20 }: LogoProps) {
  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src="/nanoclaw.png"
      alt=""
      width={size}
      height={size}
      loading="lazy"
      decoding="async"
      className={className ?? "opacity-40"}
    />
  );
}

