const LOGO_MAP: Record<string, React.ComponentType<LogoProps>> = {
  openclaw: OpenClawLogo,
  nanoclaw: NanoClawLogo,
  ironclaw: NearLogo,
  kimiclaw: ClawLogo,
  "claude-code": ClaudeCodeLogo,
  cursor: CursorLogo,
  codex: OpenAILogo,
  goose: GooseLogo,
  ollama: OllamaLogo,
  hermes: HermesLogo,
  bankrbot: BankrLogo,
};

export function PlatformLogo({
  id,
  className,
  size = 20,
}: LogoProps & { id: string }) {
  const Logo = LOGO_MAP[id];
  if (Logo) {
    return <Logo className={className} size={size} />;
  }
  return null;
}
